<?php if (!defined('ABSPATH')) { exit; } $tiles = HPPWA_Plugin::instance()->listings->developments(); ?>
<header class="hppwa-page-head"><h1>Developments</h1><p>Browse by detected Houzez location, label, type, status, or project taxonomy.</p></header><section class="hppwa-grid"><?php foreach ($tiles as $tile) : ?><a class="hppwa-tile" href="<?php echo esc_url(add_query_arg('location', $tile['slug'], home_url('/app/listings/'))); ?>"><strong><?php echo esc_html($tile['name']); ?></strong><span><?php echo esc_html($tile['count']); ?> properties</span><small><?php echo esc_html($tile['taxonomy']); ?></small></a><?php endforeach; ?></section>
